use std::collections::HashMap;

struct CacheServer {
    storage: HashMap<String, String>,
}

impl CacheServer {
    fn new() -> Self {
        CacheServer { 
            storage: HashMap::new()
        }
    }

    fn set(&mut self, key: impl AsRef<str>, value: impl AsRef<str>) {
        self.storage.insert(key.as_ref().to_string(), value.as_ref().to_string());
    }

    fn get(&self, key: &str) -> Option<&str> {
        self.storage.get(key).map(|s| s.as_str())
    }

    fn process_data_in_groups(items: &[String], window_size: usize) -> Vec<Vec<String>> {
        let mut processed_blocks = Vec::new();
        for chunk in items.windows(window_size) {
            processed_blocks.push(chunk.to_vec());
        }
        processed_blocks
    }

    fn process_data_in_chunks(items: &[String], chunk_size: usize) -> Vec<Vec<String>> {
        let mut processed_blocks = Vec::new();
        for window in items.chunks(chunk_size) {
            processed_blocks.push(window.to_vec());
        }
        processed_blocks
    }
}

fn main() {
    let cache = CacheServer::new();
    let data = vec![ 
        "key1".to_string(), "key2".to_string(), "key3".to_string(), 
        "key4".to_string(), "key5".to_string(), "key6".to_string(), 
        "key7".to_string()
    ];

    let windowed = CacheServer::process_data_in_groups(&data, 3);
    println!("Windowed results (size 3):");
    for block in windowed {
        println!("{}", block.join("|"));
    }

    let chunked = CacheServer::process_data_in_chunks(&data, 2);
    println!("nChunked results (size 2):");
    for block in chunked {
