    }
}

use std::collections::VecDeque;

fn main() {
    let raw_data = "abcdefghijklmnopqrstuvwxyz";
    let window_size = 3;

    let mut deque: VecDeque<char> = raw_data.chars().collect();
    let mut processed_windows = Vec::new();

    while deque.len() >= window_size {
        processed_windows.push(deque.iter().take(window_size).collect::<String>());
        for _ in 0..window_size {
            deque.pop_front();
        }
    }

    println!("Processed windows (sliding):");
    for window in processed_windows.iter() {
        print!(" {}", window);
        print!("; ");
    }
    println!();

    let chunk_size = 5;
    let mut current_data = raw_data.chars().collect::<String>();
    let mut processed_chunks = Vec::new();

    for chunk in current_data.as_bytes().chunks(chunk_size) {
        processed_chunks.push(String::from_utf8_lossy(chunk).to_string());
    }

    println!("Processed chunks (fixed):");
    for chunk in processed_chunks { 
        print!(" {}", chunk);
        print!("; ");
    }
    println!();
}

use std::collections::HashMap;

struct CacheEntry {
    id: u32,
    data: Vec<u8>,
}

fn process_cache(entries: Vec<CacheEntry>, window_size: usize) -> HashMap<u32, String> {
    let mut processed_map = HashMap::new();
    for chunk in entries.chunks(window_size) {
        if chunk.is_empty() {
            continue;
        }
        println!("Processing a memory block of size {}", chunk.len());
        for entry in chunk.iter() {
            let key = entry.id;
            let value = format!("Processed data for ID: {}", key);
            processed_map.insert(key, value);
        }
    }
    processed_map
}

fn main() {
    let mut all_data = Vec::new();
    for i in 0..10 { 
        all_data.push(CacheEntry { id: i as u32, data: vec![i] });
    }

    let window = 3;
    let result = process_cache(all_data, window);

    println!("nTotal unique entries processed: {}", result.len());
}

use std::collections::HashMap;
use serde::{Serialize, Deserialize};

#[derive(Debug, Clone, Serialize, Deserialize)]
struct SourceObject {
    line: usize,
    column: usize,
    original_path: String,
}

fn generate_source_map_chunks(objects: Vec<SourceObject>, window_size: usize) -> Vec<Vec<SourceObject>> {
    let mut result_chunks = Vec::new();
    for chunk in objects.windows(window_size) {
        let mut current_window: Vec<SourceObject> = chunk.iter().cloned().collect();
        result_chunks.push(current_window);
    }
    result_chunks
}

fn main() {
    let source_objects = vec![ 
        SourceObject { line: 1, column: 5, original_path: "a.js".to_string() }, 
        SourceObject { line: 2, column: 10, original_path: "b.js".to_string() }, 
        SourceObject { line: 3, column: 8, original_path: "c.js".to_string() }, 
        SourceObject { line: 4, column: 3, original_path: "d.js".to_string() }, 
        SourceObject { line: 5, column: 1, original_path: "e.js".to_string() }, 
    ];

    let window_size = 3;
    let chunks = generate_source_map_chunks(source_objects, window_size);

    for (i, chunk) in chunks.iter().enumerate() {
        println!("Processing chunk {}", i + 1);
        for obj in chunk.iter() {
            println!("  - Line: {}, Path: {}", obj.line, obj.original_path);
        }
    }
}

